#include<bits/stdc++.h>
using namespace std;

const int MAXA = 100010;
int cnt[MAXA];
queue<long long> q1, q2;
void read(int &x){ 
	int f=1;x=0;char s=getchar();
	while(s<'0'||s>'9'){if(s=='-')f=-1;s=getchar();}
	while(s>='0'&&s<='9'){x=x*10+s-'0';s=getchar();}
	x*=f;
}
int main() {
    int n;
	read(n);

    int max_val = 0;
    for(int i = 0; i < n; i++) {
        int a;
		read(a);
        cnt[a]++;
        max_val = max(max_val, a);
    }
    for(int i = 1; i <= max_val; i++) {
        while(cnt[i]--) {
            q1.push(i);
        }
    }

    long long ans = 0;
    while(!q1.empty() || q2.size() > 1) {
        long long a, b;
        if(q2.empty() || (!q1.empty() && q1.front() <= q2.front())) {
            a = q1.front();
            q1.pop();
        } else {
            a = q2.front();
            q2.pop();
        }
        if(q1.empty()) {
            b = q2.front();
            q2.pop();
        } else if(q2.empty()) {
            b = q1.front();
            q1.pop();
        } else {
            if(q1.front() <= q2.front()) {
                b = q1.front();
                q1.pop();
            } else {
                b = q2.front();
                q2.pop();
            }
        }
        long long sum = a + b;
        ans += sum;
        q2.push(sum);
    }

    printf("%lld\n", ans);
    return 0;
}
